VALUES
  ('judicial-57f41407-moex-00013', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '中華人民共和國的黨國體制不同於西方民主國家的憲政體制，有關中國政治制度的運作，下列敘述何者正確？', '["最高人民法院擁有解釋憲法的權限", "全國人民代表大會屬於法律監督機構", "國務院是人民行使最高國家權力的機關", "中央政治局常務委員會是中共的領導核心"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00014', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '依我國憲法及相關法律規定，下列人員的產生方式，何者與其他人員之任命程序明顯不同？', '["總統府秘書長", "銓敘部部長", "國家安全局局長", "檢察總長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00015', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '社會財富分配不均所導致的經濟不平等，是最常被注意到的社會階層化現象。羅倫斯曲線（LorenzCurve）以 「最貧窮的人口計算起一直到最富有人口」的人口百分比對應各個人口百分比的收入百分比的點組成的曲線， 來判斷經濟分配的狀況。下面有甲乙丙丁四個國家的曲線，請指出那一個國家的經濟不平等現象比較嚴重？', '["甲", "乙", "丙", "丁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00016', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '媒體工作者或其背後的生產機制可能無意識或有意識地採用某種意識型態進行編寫及產製，再傳播給閱聽 人。此概念稱為：', '["媒體近用", "媒體再現", "媒體集中化", "媒體娛樂化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00017', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '記者：「戴資穎從臺灣走到世界球后，怎麼撐過辛苦的練習？」戴媽媽笑說：「她從來沒抱怨，只要週末不 練球就好。十多年來的練球生涯，唯一為東京奧運破例。她主動要求在週末加練，沒想到求好心切，竟在 賽前受傷。『她在電話裡大哭！』」從佛洛依德的人格結構論述來看，媽媽敘述戴資穎為了東奧奪冠的練習 行為改變，最可能是受了何者的影響？', '["主我", "本我", "客我", "超我"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00018', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '烏克蘭是歐洲領土第二大國，在 18 世紀的俄土戰爭，俄羅斯帝國併吞了烏克蘭，大批俄國人移入。烏克 蘭的天然資源豐富，曾是蘇聯時期的農業和工業重鎮，甚至蘇聯的三個領導人赫魯雪夫（Nikita Khrushchev）、布里茲涅夫（LeonidBrezhnev）和戈巴契夫（MikhailGorbachev）也是出身烏克蘭。但是信 仰東正教的俄人與東烏克蘭人，跟信仰天主教的西烏克蘭人在宗教文化與族群上長期存在分歧，如今俄國 也利用這樣的分歧對烏克蘭國內進行挑撥，同時也挑起了戰火。參考此一歷史簡述，2022年的俄烏戰爭與 下列何者最不相關？', '["廣大領土", "豐富資源", "國家主權", "國家認同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00019', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '我國曾經面臨過朝小野大所形成的政治僵局窘境。若想要克服前述問題，可參考法國雙首長制的何種制度設計？', '["總統必須任命國會多數黨人擔任行政院長", "總統與立法委員的就職日與任期必須一致", "取消現行總統任期得連選連任一次的規定", "立法規定國防外交權屬總統，內政屬閣揆"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00020', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '甲為一個官方性的國際組織，其成立是為了確保國際間自由貿易，透過多邊諮商建立規範，降低會員國間 關稅與非關稅貿易障礙，為會員國提供穩定及可預測的貿易環境。甲為下列那個國際組織？', '["世界銀行（WorldBank）", "國際貨幣基金（InternationalMonetaryFund）", "世界貿易組織（WorldTradeOrganization）", "跨太平洋夥伴全面進步協定（ComprehensiveandProgressiveAgreementforTrans-PacificPartnership,CPTPP）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00021', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '2021年1月初，我國辦理「第十屆立法委員臺中市第二選舉區缺額補選」（第二選區含沙鹿區、龍井區、 大肚區、烏日區、霧峰區），該補選源於原選區之立法委員因罷免案通過而被解職。本次補選投票率達58.2% （當選者得票率為51.83%），成為歷次立法委員補選以來最高的投票率紀錄。請判斷下列敘述何者正確？', '["該次補選含括區域甚多，為「大選區制」", "本次補選當選者具「合法性與正當性」", "本次補選之立委屬「不分區立委」之範疇", "本次補選投票率過半係因採間接選舉制度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00022', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '下列何者不是隸屬我國行政院之行政機關？', '["中央銀行", "國立故宮博物院", "審計部", "國軍退除役官兵輔導委員會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
